        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.bubbleUp();
        }
        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.bubbleDown();
            return min;
        }
        bubbleUp() {
            let index = this.heap.length - 1;
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }
        bubbleDown() {
            let index = 0;
            const length = this.heap.length;
            while (index < length) {
                const leftIndex = 2 * index + 1;
                const rightIndex = 2 * index + 2;
                let smallestIndex = index;
                if (leftIndex < length && this.heap[leftIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = leftIndex;
                }
                if (rightIndex < length && this.heap[rightIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = rightIndex;
                }
                if (smallestIndex !== index) {
                    [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
                    index = smallestIndex;
                } else {
                    break;
                }
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, s, e] of edges) {
        adj[u].push({ v, s, e });
    }

    const pq = new PriorityQueue();
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    pq.push([0, 0]);

    while (!pq.isEmpty()) {
        const [currentTime, currentNode] = pq.pop();
        if (currentNode === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[currentNode]) {
            continue;
        }
        for (const edge of adj[currentNode]) {
